def parse_csv_line(line):
    fields = []
    cur = []
    in_quotes = False
    i = 0
    while i < len(line):
        c = line[i]
        if in_quotes:
            if c == '"':
                if i + 1 < len(line) and line[i+1] == '"':
                    cur.append('"')
                    i += 2
                    continue
                in_quotes = False
            else:
                cur.append(c)
        else:
            if c == '"':
                in_quotes = True
            elif c == ',':
                fields.append(''.join(cur))
                cur = []
            else:
                cur.append(c)
        i += 1
    fields.append(''.join(cur))
    return fields

